import React, { useState, useEffect } from 'react';
import { getBooks, searchBooks, borrowBook, joinWaitingList } from '../api/api';

function BookList({ currentUserId }) {
  const [books, setBooks] = useState([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState({ text: '', isError: false });

  const fetchBooks = async (query = '') => {
    setLoading(true);
    try {
      let response;
      if (query) {
        response = await searchBooks(query);
      } else {
        response = await getBooks();
      }
      setBooks(response.data);
    } catch (error) {
      console.error("Error fetching books:", error);
      showMessage("Failed to load books. Please check backend status.", true);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchBooks();
  }, []);

  const handleSearchSubmit = (e) => {
    e.preventDefault();
    fetchBooks(searchQuery);
  };

  const showMessage = (text, isError = false) => {
    setMessage({ text, isError });
    setTimeout(() => setMessage({ text: '', isError: false }), 5000);
  };

  const handleBorrow = async (bookId, title) => {
    try {
      await borrowBook(currentUserId, bookId);
      showMessage(`Successfully borrowed '${title}'! Check 'My Borrows' tab.`, false);
      fetchBooks(searchQuery);
    } catch (error) {
      const errMsg = error.response?.data?.error || `Failed to borrow book.`;
      showMessage(errMsg, true);
    }
  };

  const handleJoinWaitingList = async (bookId, title) => {
    try {
      const response = await joinWaitingList(currentUserId, bookId);
      const position = response.data.queuePosition;
      showMessage(`Added to waiting list for '${title}'! Your queue position is ${position}.`, false);
      fetchBooks(searchQuery);
    } catch (error) {
      const errMsg = error.response?.data?.error || `Failed to join waiting list.`;
      showMessage(errMsg, true);
    }
  };

  return (
    <div className="page">
      <div className="page-header">
        <h2>Book Catalog</h2>
        <span>Active User ID: <strong>{currentUserId}</strong></span>
      </div>

      {message.text && (
        <div className={`alert-box ${message.isError ? 'alert-error' : 'alert-success'}`}>
          {message.text}
        </div>
      )}

      <form onSubmit={handleSearchSubmit} className="search-bar">
        <input
          type="text"
          placeholder="Search books by title..."
          value={searchQuery}
          onChange={(e) => setSearchQuery(e.target.value)}
        />
        <button type="submit" className="btn btn-primary">Search</button>
        {searchQuery && (
          <button
            type="button"
            className="btn btn-secondary"
            onClick={() => {
              setSearchQuery('');
              fetchBooks('');
            }}
          >
            Clear
          </button>
        )}
      </form>

      {loading ? (
        <p>Loading catalog...</p>
      ) : books.length === 0 ? (
        <p>No books found.</p>
      ) : (
        <table>
          <thead>
            <tr>
              <th>Title</th>
              <th>Author</th>
              <th>ISBN</th>
              <th>Total Copies</th>
              <th>Available Copies</th>
              <th>Action</th>
            </tr>
          </thead>
          <tbody>
            {books.map((book) => (
              <tr key={book.id}>
                <td><strong>{book.title}</strong></td>
                <td>{book.author}</td>
                <td><code>{book.isbn}</code></td>
                <td>{book.totalCopies}</td>
                <td>
                  <span className={`badge ${book.availableCopies > 0 ? 'badge-success' : 'badge-danger'}`}>
                    {book.availableCopies} available
                  </span>
                </td>
                <td>
                  {book.availableCopies > 0 ? (
                    <button
                      className="btn btn-success btn-sm"
                      onClick={() => handleBorrow(book.id, book.title)}
                    >
                      Borrow
                    </button>
                  ) : (
                    <button
                      className="btn btn-warning btn-sm"
                      onClick={() => handleJoinWaitingList(book.id, book.title)}
                    >
                      Join Waiting List
                    </button>
                  )}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </div>
  );
}

export default BookList;
